(function () {
  function getQuery() {
    var params = new URLSearchParams(window.location.search);
    return (params.get("q") || "").trim();
  }

  function escapeHtml(value) {
    return String(value)
      .replace(/&/g, "&amp;")
      .replace(/</g, "&lt;")
      .replace(/>/g, "&gt;")
      .replace(/"/g, "&quot;")
      .replace(/'/g, "&#039;");
  }

  function renderCard(movie) {
    var tags = movie.tags.slice(0, 3).map(function (tag) {
      return "<span>" + escapeHtml(tag) + "</span>";
    }).join("");
    return [
      "<article class=\"movie-card movie-card-medium\">",
      "<a class=\"poster-link\" href=\"./" + escapeHtml(movie.file) + "\" aria-label=\"" + escapeHtml(movie.title) + "\">",
      "<img src=\"" + escapeHtml(movie.cover) + "\" alt=\"" + escapeHtml(movie.title) + "\" loading=\"lazy\">",
      "<span class=\"score-badge\">" + escapeHtml(movie.rating) + "</span>",
      "</a>",
      "<div class=\"movie-card-body\">",
      "<div class=\"movie-meta-line\"><span>" + escapeHtml(movie.year) + "</span><span>" + escapeHtml(movie.region) + "</span><span>" + escapeHtml(movie.type) + "</span></div>",
      "<h3><a href=\"./" + escapeHtml(movie.file) + "\">" + escapeHtml(movie.title) + "</a></h3>",
      "<p>" + escapeHtml(movie.oneLine) + "</p>",
      "<div class=\"tag-row\">" + tags + "</div>",
      "</div>",
      "</article>"
    ].join("");
  }

  function setupSearch() {
    var input = document.querySelector("[data-search-input]");
    var form = document.querySelector("[data-search-form]");
    var results = document.querySelector("[data-search-results]");
    var hint = document.querySelector("[data-search-hint]");
    if (!input || !form || !results || !window.SEARCH_MOVIES) {
      return;
    }
    var query = getQuery();
    input.value = query;

    function search(value) {
      var keyword = value.trim().toLowerCase();
      if (!keyword) {
        results.innerHTML = "";
        if (hint) {
          hint.textContent = "输入关键词后显示匹配影片。";
        }
        return;
      }
      var words = keyword.split(/\s+/).filter(Boolean);
      var matched = window.SEARCH_MOVIES.filter(function (movie) {
        var text = [movie.title, movie.region, movie.type, movie.year, movie.genre, movie.tags.join(" "), movie.oneLine].join(" ").toLowerCase();
        return words.every(function (word) {
          return text.indexOf(word) !== -1;
        });
      }).slice(0, 120);
      if (hint) {
        hint.textContent = matched.length ? "已匹配到相关影片，点击卡片进入详情页。" : "未找到匹配影片，可更换关键词继续搜索。";
      }
      results.innerHTML = matched.map(renderCard).join("");
    }

    form.addEventListener("submit", function (event) {
      event.preventDefault();
      var value = input.value.trim();
      var url = new URL(window.location.href);
      if (value) {
        url.searchParams.set("q", value);
      } else {
        url.searchParams.delete("q");
      }
      window.history.replaceState(null, "", url.toString());
      search(value);
    });

    search(query);
  }

  document.addEventListener("DOMContentLoaded", setupSearch);
})();
